// ── Domain interface — your app code talks to this ──
abstract class Analytics {
  Future<void> track(String event, {Map<String, Object?> props});
  Future<void> identify(String userId, {Map<String, Object?> traits});
}

// ── Adapter for SDK A (Mixpanel-like) ──
class MixpanelAnalyticsAdapter implements Analytics {
  final MixpanelSDK _mp;        // foreign object
  MixpanelAnalyticsAdapter(this._mp);

  @override
  Future<void> track(String event, {Map<String, Object?> props = const {}}) =>
      _mp.recordEvent(name: event, payload: props.cast<String, Object>());

  @override
  Future<void> identify(String userId, {Map<String, Object?> traits = const {}}) async {
    _mp.alias(userId);
    _mp.setProfile(traits);
  }
}

// ── Adapter for SDK B (Amplitude-like) — same interface, different SDK ──
class AmplitudeAnalyticsAdapter implements Analytics {
  final AmplitudeClient _amp;
  AmplitudeAnalyticsAdapter(this._amp);

  @override
  Future<void> track(String event, {Map<String, Object?> props = const {}}) async {
    await _amp.logEvent(eventType: event, eventProperties: props);
  }

  @override
  Future<void> identify(String userId, {Map<String, Object?> traits = const {}}) async {
    _amp.setUserId(userId);
    if (traits.isNotEmpty) await _amp.setUserProperties(traits);
  }
}

// ── Composite adapter — fan out to many SDKs ──
class CompositeAnalytics implements Analytics {
  final List<Analytics> _children;
  CompositeAnalytics(this._children);

  @override
  Future<void> track(String event, {Map<String, Object?> props = const {}}) =>
      Future.wait(_children.map((a) => a.track(event, props: props)));

  @override
  Future<void> identify(String userId, {Map<String, Object?> traits = const {}}) =>
      Future.wait(_children.map((a) => a.identify(userId, traits: traits)));
}

// ── App code — never sees the foreign SDKs ──
final analytics = CompositeAnalytics([
  MixpanelAnalyticsAdapter(mixpanel),
  AmplitudeAnalyticsAdapter(amplitude),
]);
await analytics.track('checkout_started', props: {'cart_size': 3});

// ── Interface ──
abstract class UserRepository {
  Future<User> getUser(int id);
  Future<void> updateUser(User user);
}

// ── Concrete ──
class ApiUserRepository implements UserRepository {
  final Dio _dio;
  ApiUserRepository(this._dio);
  @override Future<User> getUser(int id) async =>
      User.fromJson((await _dio.get('/users/$id')).data);
  @override Future<void> updateUser(User user) async =>
      _dio.put('/users/${user.id}', data: user.toJson());
}

// ── Decorator: caching ──
class CachingUserRepository implements UserRepository {
  final UserRepository _inner;
  final Map<int, User> _cache = {};
  CachingUserRepository(this._inner);

  @override
  Future<User> getUser(int id) async {
    final hit = _cache[id];
    if (hit != null) return hit;
    final user = await _inner.getUser(id);
    return _cache[id] = user;
  }

  @override
  Future<void> updateUser(User user) async {
    await _inner.updateUser(user);
    _cache[user.id] = user;            // keep cache fresh
  }
}

// ── Decorator: logging ──
class LoggingUserRepository implements UserRepository {
  final UserRepository _inner;
  LoggingUserRepository(this._inner);

  @override
  Future<User> getUser(int id) async {
    final sw = Stopwatch()..start();
    try {
      return await _inner.getUser(id);
    } finally {
      log('getUser($id) took ${sw.elapsedMilliseconds}ms');
    }
  }

  @override
  Future<void> updateUser(User user) => _inner.updateUser(user);
}

// ── Compose at the edge of the app ──
final repo = LoggingUserRepository(
  CachingUserRepository(
    ApiUserRepository(dio),
  ),
);
// repo.getUser(1) → log → cache miss → api → cache fill
// repo.getUser(1) → log → cache hit  → return

// ── Mixin alternative for intrinsic behaviour ──
mixin TimedRepository on UserRepository {
  @override Future<User> getUser(int id) async {
    final sw = Stopwatch()..start();
    final u = await super.getUser(id);
    log('${runtimeType}.getUser took ${sw.elapsedMilliseconds}ms');
    return u;
  }
}
class TimedApiUserRepository = ApiUserRepository with TimedRepository;
