sealed class Command {
  Future<void> execute();
  Future<void> undo();
}

// Concrete commands carry both the action and its inverse data
class RenameUser extends Command {
  final UserRepository repo;
  final int userId;
  final String newName;
  String? _previousName;            // captured during execute()

  RenameUser(this.repo, this.userId, this.newName);

  @override
  Future<void> execute() async {
    final user = await repo.getUser(userId);
    _previousName = user.name;
    await repo.updateUser(user.copyWith(name: newName));
  }

  @override
  Future<void> undo() async {
    if (_previousName == null) return;
    final user = await repo.getUser(userId);
    await repo.updateUser(user.copyWith(name: _previousName!));
  }
}

class DeleteUser extends Command {
  final UserRepository repo;
  final int userId;
  User? _deletedSnapshot;

  DeleteUser(this.repo, this.userId);

  @override
  Future<void> execute() async {
    _deletedSnapshot = await repo.getUser(userId);
    await repo.delete(userId);
  }

  @override
  Future<void> undo() async {
    if (_deletedSnapshot == null) return;
    await repo.create(_deletedSnapshot!);  // restore exact prior state
  }
}

// ── Runner with undo/redo stacks ──
class CommandRunner {
  final _undo = <Command>[];
  final _redo = <Command>[];

  Future<void> run(Command c) async {
    await c.execute();
    _undo.add(c);
    _redo.clear();              // a fresh action invalidates redo history
  }

  Future<void> undo() async {
    if (_undo.isEmpty) return;
    final c = _undo.removeLast();
    await c.undo();
    _redo.add(c);
  }

  Future<void> redo() async {
    if (_redo.isEmpty) return;
    final c = _redo.removeLast();
    await c.execute();
    _undo.add(c);
  }
}

// ── Usage from a button — the button doesn't know what's inside the command ──
