// ── 1) State pattern — rich, polymorphic behaviour ──
abstract class TrafficLight {
  String get color;
  TrafficLight next();
  Duration get duration;
}
class GreenLight  extends TrafficLight {
  @override String get color => 'green';
  @override TrafficLight next() => YellowLight();
  @override Duration get duration => const Duration(seconds: 30);
}
class YellowLight extends TrafficLight {
  @override String get color => 'yellow';
  @override TrafficLight next() => RedLight();
  @override Duration get duration => const Duration(seconds: 5);
}
class RedLight    extends TrafficLight {
  @override String get color => 'red';
  @override TrafficLight next() => GreenLight();
  @override Duration get duration => const Duration(seconds: 30);
}

class Intersection {
  TrafficLight current = GreenLight();
  void tick() => current = current.next();
}
// Transitions live INSIDE each state. Adding a new state edits one class.

// ── 2) Sealed classes — Dart 3 idiom for inert state ──
sealed class AuthState {}
final class Anonymous      extends AuthState { const Anonymous(); }
final class Authenticating extends AuthState { final String email; Authenticating(this.email); }
final class Authenticated  extends AuthState { final User user; Authenticated(this.user); }
final class AuthFailed     extends AuthState { final Object error; AuthFailed(this.error); }

class AuthNotifier extends StateNotifier<AuthState> {
  AuthNotifier() : super(const Anonymous());
  Future<void> signIn(String email, String pwd) async {
    state = Authenticating(email);
    try { state = Authenticated(await api.signIn(email, pwd)); }
    catch (e) { state = AuthFailed(e); }
  }
}

// UI consumer — exhaustive on the sealed family
Widget render(AuthState s) => switch (s) {
  Anonymous()                    => const SignInPage(),
  Authenticating(:final email)   => Splash(label: 'Signing in $email…'),
  Authenticated(:final user)     => HomePage(user: user),
  AuthFailed(:final error)       => ErrorPage(error: error),
  // ❌ Add a new subtype — every switch fails to compile until handled
};
