// ── BLoC — explicit events and states ──
import 'package:flutter_bloc/flutter_bloc.dart';

// Events
sealed class SearchEvent {}
final class QueryChanged extends SearchEvent { final String q; QueryChanged(this.q); }
final class Submitted    extends SearchEvent {}

// States
sealed class SearchState {}
final class Idle    extends SearchState { const Idle(); }
final class Loading extends SearchState { const Loading(); }
final class Loaded  extends SearchState { final List<Hit> hits; Loaded(this.hits); }
final class Failed  extends SearchState { final Object err; Failed(this.err); }

class SearchBloc extends Bloc<SearchEvent, SearchState> {
  final SearchRepo repo;
  SearchBloc(this.repo) : super(const Idle()) {
    // ✅ Switch-map: a new query cancels the in-flight previous request
    on<QueryChanged>(
      (event, emit) async {
        if (event.q.isEmpty) { emit(const Idle()); return; }
        emit(const Loading());
        try { emit(Loaded(await repo.search(event.q))); }
        catch (e) { emit(Failed(e)); }
      },
      transformer: (events, mapper) => events
          .debounceTime(const Duration(milliseconds: 250))
          .switchMap(mapper),
    );
  }
}

// ── Test BLoC without widgets ──
blocTest<SearchBloc, SearchState>(
  'emits Loaded after Loading on QueryChanged',
  build: () => SearchBloc(FakeRepo()),
  act: (b) => b.add(QueryChanged('flutter')),
  wait: const Duration(milliseconds: 300),
  expect: () => [const Loading(), isA<Loaded>()],
);

